export function renderCombinedProgress(
  orchestratorActivity: OrchestratorActivity,
  specialistName: string,
  feedState: ActivityFeedState,
  goal?: string,
): string {
  advanceSpinner();

  // Error state: shows retry count or "✗ Step failed: <msg>"
  if (feedState.errored) { ... }

  const lines: string[] = [];

  // Goal line: ◆ <goal>
  if (goal) {
    lines.push(`◆ ${goal}`);
  } else if (feedState.goal) {
    lines.push(`◆ ${feedState.goal}`);
  }

  // Progress dots: ●● [2/4]
  if (showFeedProgress) {
    lines.push(`${dots} [${feedCompleted}/${feedTotal}]`);
  }

  // ORCHESTRATOR STEPS (Layer 1) — iterated by index
  for (let i = 0; i < orcTotal; i++) {
    const step = orchestratorActivity.steps[i];
    const isCurrent = i === orchestratorActivity.currentStep;

    if (step.completed) {
      lines.push(`✓ ${step.label} (${duration})`);       // 2-space indent
    } else if (isCurrent) {
      // NESTED: feed steps (Layer 2) rendered HERE inside current orc step
      if (feedState.steps.length > 0 && feedState.currentStep >= 0) {
        for (let fi = 0; fi < feedState.steps.length; fi++) {
          const fs = feedState.steps[fi];
          if (fs.completed) {
            lines.push(`  ✓ ${fs.label} (${dur})`);      // 2-space indent
          } else if (isFeedCurrent) {
            lines.push(`  ${spinner} ${fs.label}...`);    // 2-space indent
          } else {
            lines.push(`  ○ ${fs.label}`);                // 2-space indent
          }
          // Substeps (tool calls) — 4-space indent
          for (const sub of visibleSubs) {
            if (sub.completed) {
              lines.push(`    ✓ ${sub.label} (${subDur})`);    // 4-space indent
            } else {
              lines.push(`    ${spinner} ${sub.label}...`);    // 4-space indent
            }
          }
        }
      } else {
        lines.push(`  ${spinner} Working...`);
      }
    } else if (isPending) {
      lines.push(`○ ${step.label}`);
    }
  }
  return lines.join("\n");
}
```

**Rendering hierarchy:**
| Level | Indent | Icon (active) | Icon (completed) | Icon (pending) |
|-------|--------|--------------|-------------------|----------------|
| Orc step | 0 | `<spinner> <label>...` | `✓ <label> (<dur>)` | `○ <label>` |
| Feed step | 2-space | `<spinner> <label>...` | `✓ <label> (<dur>)` | `○ <label>` |
| Substep | 4-space | `<spinner> <label>...` | `✓ <label> (<dur>)` | — |

**Key detail:** Feed steps only render when inside the *current* orchestrator step. Completed orc steps collapse to a single `✓` line.

